  // OVDR
  GetAgreementsBalancesBackwardCSV() {
    this.showLoader = true;
    if (this.parametersForm.valid) {
      const request: GetAgreementsBalancesRequest = {
        start_date: this.parametersForm.controls.start_date.value,
        end_date: this.parametersForm.controls.end_date.value,
        calc_date: this.parametersForm.controls.calc_date.value,
        all_branches: 0,
        branch_codes_list: this.ovdrBranchesCodeString,
        all_loan_types: 0,
        loan_types_list: this.ovdrLoanTypesCodesString,
        all_officers: 0,
        officer_keys_list: this.parametersForm.controls.officer_keys_list.value,
      };

      this.http
        .post(
          this.env.API_URL +
            `api/Agreement/GetAgreementsBalancesBackwardRepForCSV`,
          {
            start_date: request.start_date,
            end_date: request.end_date,
            calc_date: request.calc_date,
            all_branches: request.all_branches,
            branch_codes_list: request.branch_codes_list,
            all_loan_types: request.all_loan_types,
            loan_types_list: request.loan_types_list,
            all_officers: request.all_officers,
            officer_keys_list: request.officer_keys_list,
          },
          { responseType: "blob" }
        )
        .subscribe({
          next: (response: Blob) => {
            const currentDate = new Date();
            const dateString = currentDate.toLocaleDateString("en-US");
            const timeString = currentDate.toLocaleTimeString("en-US", {
              hour: "numeric",
              minute: "numeric",
              hour12: false,
            });
            const formattedDateTime = `${dateString} ${timeString}`;

            const filename =
              formattedDateTime + " " + "AgreementsBalancesBackwardRep.csv";
            const options = { autoBom: false };
            this.showLoader = false;
            saveAs(response, filename, options);
            this.showLoader = false;
          },
          error: (err) => {
            console.log(err);
          },
        });
    }
  }
